# Routes: results (plot catalog + Plotly JSON + table data)

using JSON3, CSV, DataFrames

## Plot catalog
#
# Plots are stored as Plotly JSON files in:
#   projects/{study}/{run}/analysis/Plots/{plot_id}.json
#
# They are generated by analyse_run / analyse_study. PDFs are generated on
# demand via the /files/ endpoint.

function _plot_dir(study::String, run::String)
    joinpath(ServerState.projects_dir(), study, run, "analysis", "Plots")
end

function _study_plot_dir(study::String)
    joinpath(ServerState.projects_dir(), study, "analysis", "Plots")
end

function _plot_catalog(plot_dir::String, stage::String)
    isdir(plot_dir) || return []
    map(filter(f -> endswith(f, ".json"), readdir(plot_dir))) do f
        id    = splitext(f)[1]
        label = replace(id, "_" => " ") |> titlecase
        (; id, label, stage)
    end
end

@get "/api/v1/studies/{study}/runs/{run}/results/plots" function(req,
                                                                  study::String,
                                                                  run::String)
    study in _study_names() || return json_error(404, "study_not_found",
                                                     "Study '$study' not found")
    run in _run_names(study) || return json_error(404, "run_not_found",
                                                      "Run '$run' not found")
    catalog = _plot_catalog(_plot_dir(study, run), "analyse_run")
    json(catalog)
end

@get "/api/v1/studies/{study}/runs/{run}/results/plots/{plot_id}" function(req,
                                                                             study::String,
                                                                             run::String,
                                                                             plot_id::String)
    study in _study_names() || return json_error(404, "study_not_found",
                                                     "Study '$study' not found")
    run in _run_names(study) || return json_error(404, "run_not_found",
                                                      "Run '$run' not found")
    path = joinpath(_plot_dir(study, run), plot_id * ".json")
    isfile(path) || return json_error(404, "plot_not_found",
                                          "Plot '$plot_id' not found for run '$run'")
    HTTP.Response(200,
        ["Content-Type" => "application/json"],
        body = read(path, String))
end

@get "/api/v1/studies/{study}/results/plots" function(req, study::String)
    study in _study_names() || return json_error(404, "study_not_found",
                                                     "Study '$study' not found")
    catalog = _plot_catalog(_study_plot_dir(study), "analyse_study")
    json(catalog)
end

@get "/api/v1/studies/{study}/results/plots/{plot_id}" function(req,
                                                                  study::String,
                                                                  plot_id::String)
    study in _study_names() || return json_error(404, "study_not_found",
                                                     "Study '$study' not found")
    path = joinpath(_study_plot_dir(study), plot_id * ".json")
    isfile(path) || return json_error(404, "plot_not_found",
                                          "Plot '$plot_id' not found for study '$study'")
    HTTP.Response(200,
        ["Content-Type" => "application/json"],
        body = read(path, String))
end

## Tables

function _merge_dir(study::String, run::String)
    joinpath(ServerState.projects_dir(), study, run, "merged")
end

@get "/api/v1/studies/{study}/runs/{run}/results/tables" function(req,
                                                                    study::String,
                                                                    run::String)
    study in _study_names() || return json_error(404, "study_not_found",
                                                     "Study '$study' not found")
    run in _run_names(study) || return json_error(404, "run_not_found",
                                                      "Run '$run' not found")
    dir = _merge_dir(study, run)
    isdir(dir) || return json([])

    catalog = map(filter(f -> endswith(f, ".csv"), readdir(dir))) do f
        path  = joinpath(dir, f)
        id    = splitext(f)[1]
        label = replace(id, "_" => " ") |> titlecase
        rows  = try
            nrow(CSV.read(path, DataFrame; limit=0))
        catch
            0
        end
        (; id, label, rows)
    end
    json(catalog)
end

@get "/api/v1/studies/{study}/runs/{run}/results/tables/{table}" function(req,
                                                                            study::String,
                                                                            run::String,
                                                                            table::String)
    study in _study_names() || return json_error(404, "study_not_found",
                                                     "Study '$study' not found")
    run in _run_names(study) || return json_error(404, "run_not_found",
                                                      "Run '$run' not found")
    path = joinpath(_merge_dir(study, run), table * ".csv")
    isfile(path) || return json_error(404, "table_not_found",
                                          "Table '$table' not found for run '$run'")

    params   = queryparams(req)
    page     = parse(Int, get(params, "page",     "1"))
    per_page = parse(Int, get(params, "per_page", "100"))
    filter_q = get(params, "filter", nothing)

    df = CSV.read(path, DataFrame)
    if !isnothing(filter_q)
        mask = any(col -> any(x -> occursin(filter_q, string(x)), skipmissing(df[!, col])),
                   names(df))
        # Row-wise filter: keep rows where any string column contains filter_q
        df = filter(row -> any(col -> occursin(filter_q, string(row[col])),
                               names(df)), df)
    end

    total = nrow(df)
    start = (page - 1) * per_page + 1
    stop  = min(start + per_page - 1, total)
    page_df = start <= total ? df[start:stop, :] : df[1:0, :]

    json((; total, page, per_page, rows=JSON3.read(JSON3.write(page_df))))
end
